752	export function emitFiles(
753	    resolver: EmitResolver,
754	    host: EmitHost,
755	    targetSourceFile: SourceFile | undefined,
756	    { scriptTransformers, declarationTransformers }: EmitTransformers,
757	    emitOnly: boolean | EmitOnly | undefined,
758	    onlyBuildInfo: boolean,
759	    forceDtsEmit?: boolean,
760	    skipBuildInfo?: boolean,
761	): EmitResult {
762	    // Why var? It avoids TDZ checks in the runtime which can be costly.
763	    // See: https://github.com/microsoft/TypeScript/issues/52924
764	    /* eslint-disable no-var */
765	    var compilerOptions = host.getCompilerOptions();
766	    var sourceMapDataList: SourceMapEmitResult[] | undefined = (compilerOptions.sourceMap || compilerOptions.inlineSourceMap || getAreDeclarationMapsEnabled(compilerOptions)) ? [] : undefined;
767	    var emittedFilesList: string[] | undefined = compilerOptions.listEmittedFiles ? [] : undefined;
768	    var emitterDiagnostics = createDiagnosticCollection();
769	    var newLine = getNewLineCharacter(compilerOptions);
770	    var writer = createTextWriter(newLine);
771	    var { enter, exit } = performance.createTimer("printTime", "beforePrint", "afterPrint");
772	    var emitSkipped = false;
773	    /* eslint-enable no-var */
774	
775	    // Emit each output file
776	    enter();
777	    forEachEmittedFile(
778	        host,
779	        emitSourceFileOrBundle,
780	        getSourceFilesToEmit(host, targetSourceFile, forceDtsEmit),
781	        forceDtsEmit,
782	        onlyBuildInfo,
